    public static String decimalToBinary(double num, int k_prec) {
        StringBuilder binary = new StringBuilder();
        int integral = (int) num;
        double fractional = num - integral;
        while (integral > 0) {
            int rem = integral % 2;
            binary.append(rem);
            integral /= 2;
        }
        binary.reverse();
        binary.append('.');
        while (k_prec-- > 0) {
            fractional *= 2;
            int fractBit = (int) fractional;
            if (fractBit == 1) {
                fractional -= fractBit;
                binary.append(1);
            } else {
                binary.append(0);
            }
        }
        return binary.toString();
    }

